",
            "content": "/**
 * Portum — OpenAI-compatible chat completions gateway.
 *
 * Endpoints:
 *   POST /v1/chat/completions  — route to upstream provider
 *   GET  /health               — basic health check
 *   GET  /health/providers     — per-provider key + reachability check
 *   GET  /stats                — aggregate stats
 *   GET  /audit                — last 50 requests with full detail
 *   GET  /                     — live dashboard (HTML)
 *   GET  /version              — version information
 */

import Fastify, { type FastifyReply, type FastifyRequest } from "fastify";
import {
  routeRequest,
  getProviderForModel,
  getAllProviders,
  type ChatCompletionRequest,
  type ChatCompletionResponse,
  type ChatCompletionUsage,
  type ProviderName,
  type RouteResult,
} from "./router.js";

const PORT = Number(process.env.PORT ?? 18797);
const HOST = process.env.HOST ?? "0.0.0.0";

// ─── Audit Log ──────────────────────────────────────────────────────

interface AuditEntry {
  id: number;
  timestamp: string;
  model: string;
  provider: ProviderName;
  responseTimeMs: number;
  usage: ChatCompletionUsage;
  estimatedCostUsd: number;
  status: "ok" | "error";
  errorMessage: string | null;
  responsePreview: string;
}

const AUDIT_MAX = 50;
const auditLog: AuditEntry[] = [];
let auditSeq = 0;

function recordAudit(result: RouteResult, request: ChatCompletionRequest): AuditEntry {
  const preview = result.error
    ? result.error.message.slice(0, 200)
    : (result.response.choices[0]?.message?.content ?? "").slice(0, 200);

  const entry: AuditEntry = {
    id: ++auditSeq,
    timestamp: new Date().toISOString(),
    model: request.model,
    provider: result.provider,
    responseTimeMs: result.responseTimeMs,
    usage: result.response.usage,
    estimatedCostUsd: result.estimatedCostUsd,
    status: result.error ? "error" : "ok",
    errorMessage: result.error?.message ?? null,
    responsePreview: preview,
  };

  auditLog.push(entry);
  if (auditLog.length > AUDIT_MAX) auditLog.shift();
  return entry;
}

// ─── Aggregate Stats ────────────────────────────────────────────────

const requestCountsByProvider: Record<ProviderName, number> = {
  openai: 0,
  anthropic: 0,
  modelstudio: 0,
  minimax: 0,
  openrouter: 0,
};
const modelCounts: Record<string, number> = {};

let totalRequests = 0;
let totalErrors = 0;
let totalResponseTimeMs = 0;
let totalPromptTokens = 0;
let totalCompletionTokens = 0;
let totalTokens = 0;
let totalCostUsd = 0;
const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
let todayCostUsd = 0;

function recordStats(entry: AuditEntry): void {
  totalRequests += 1;
  if (entry.status === "error") totalErrors += 1;
  requestCountsByProvider[entry.provider] += 1;
  totalResponseTimeMs += entry.responseTimeMs;
  totalPromptTokens += entry.usage.prompt_tokens;
  totalCompletionTokens += entry.usage.completion_tokens;
  totalTokens += entry.usage.total_tokens;
  totalCostUsd += entry.estimatedCostUsd;
  modelCounts[entry.model] = (modelCounts[entry.model] ?? 0) + 1;

  if (new Date(entry.timestamp) >= todayStart) {
    todayCostUsd += entry.estimatedCostUsd;
  }
}

