const fastify = Fastify({
  logger: { level: process.env.LOG_LEVEL ?? "info" },
});

// ─── GET / — Dashboard ──────────────────────────────────────────────

fastify.get("/", async (_request, reply) => {
  reply.type("text/html").send(dashboardHtml());
