    apiKeyEnv: "DASHSCOPE_API_KEY",
  },
  minimax: {
    name: "minimax",
    // Use the OpenAI-compatible endpoint, not chatcompletion_pro
    url: "https://api.minimax.chat/v1/chat/completions",
    apiKeyEnv: "MINIMAX_API_KEY",
  },
  openrouter: {
    name: "openrouter",
    url: "https://openrouter.ai/api/v1/chat/completions",
    apiKeyEnv: "OPENROUTER_API_KEY",
  },
};

export function getAllProviders(): Record<ProviderName, { url: string; apiKeyEnv: string }> {
  const out: Record<string, { url: string; apiKeyEnv: string }> = {};
  for (const [name, cfg] of Object.entries(PROVIDERS)) {
    out[name] = { url: cfg.url, apiKeyEnv: cfg.apiKeyEnv };
  }
  return out as Record<ProviderName, { url: string; apiKeyEnv: string }>;
}

// ─── Cost Estimation ────────────────────────────────────────────────
// Rough $/1K-token rates. Good enough for dashboard estimates.

const COST_PER_1K: Record<string, { input: number; output: number }> = {
  "gpt-4o":          { input: 0.0025, output: 0.01 },
  "gpt-4o-mini":     { input: 0.00015, output: 0.0006 },
  "g
// ... [truncated]",
        "rawModelResponse": "/**
 * Portum — OpenAI-compatible chat completions gateway.
 *
 * Endpoints:
 *   POST /v1/chat/completions  — route to upstream provider
 *   GET  /health               — basic health check
 *   GET  /health/providers     — per-provider key + reachability check
 *   GET  /stats                — aggregate stats
 *   GET  /audit                — last 50 requests with full detail
 *   GET  /                     — live dashboard (HTML)
 *   GET  /version              — version information
 */

import Fastify, { type FastifyReply, type FastifyRequest } from "fastify";
import {
  routeRequest,
  getProviderForModel,
  getAllProviders,
  type ChatCompletionRequest,
  type ChatCompletionResponse,
  type ChatCompletionUsage,
  type ProviderName,
  type RouteResult,
} from "./router.js";

const PORT = Number(process.env.PORT ?? 18797);
const HOST = process.env.HOST ?? "0.0.0.0";

// ─── Audit Log ──────────────────────────────────────────────────────

interface AuditEntry {
  id: number;
  timestamp: string;
  model: string;
  provider: ProviderName;
  responseTimeMs: number;
  usage: ChatCompletionUsage;
  estimatedCostUsd: number;
  status: "ok" | "error";
  errorMessage: string | null;
  responsePreview: string;
}

const AUDIT_MAX = 50;
const auditLog: AuditEntry[] = [];
let auditSeq = 0;

function recordAudit(result: RouteResult, request: ChatCompletionRequest): AuditEntry {
  const preview = result.error
    ? result.error.message.slice(0, 200)
    : (result.response.choices[0]?.message?.content ?? "").slice(0, 200);

  const entry: AuditEntry = {
    id: ++auditSeq,
    timestamp: new Date().toISOString(),
    model: request.model,
    provider: result.provider,
    responseTimeMs: result.responseTimeMs,
    usage: result.response.usage,
    estimatedCostUsd: result.estimatedCostUsd,
    status: result.error ? "error" : "ok",
    errorMessage: result.error?.message ?? null,
    responsePreview: preview,
  };

  auditLog.push(entry);
  if (auditLog.length > AUDIT_MAX) auditLog.shift();
  return entry;
}

// ─── Aggregate Stats ────────────────────────────────────────────────

const requestCountsByProvider: Record<ProviderName, number> = {
  openai: 0,
  anthropic: 0,
  modelstudio: 0,
  minimax: 0,
  openrouter: 0,
};
const modelCounts: Record<string, number> = {};

let totalRequests = 0;
let totalErrors = 0;
let totalResponseTimeMs = 0;
let totalPromptTokens = 0;
let totalCompletionTokens = 0;
let totalTokens = 0;
let totalCostUsd = 0;
const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
let todayCostUsd = 0;

function recordStats(entry: AuditEntry): void {
  totalRequests += 1;
  if (entry.status === "error") totalErrors += 1;
  requestCountsByProvider[entry.provider] += 1;
  totalResponseTimeMs += entry.responseTimeMs;
  totalPromptTokens += entry.usage.prompt_tokens;
  totalCompletionTokens += entry.usage.completion_tokens;
  totalTokens += entry.usage.total_tokens;
  totalCostUsd += entry.estimatedCostUsd;
  modelCounts[entry.model] = (modelCounts[entry.model] ?? 0) + 1;

  if (new Date(entry.timestamp) >= todayStart) {
    todayCostUsd += entry.estimatedCostUsd;
  }
}

// ─── Server ─────────────────────────────────────────────────────────

const fastify = Fastify({
  logger: { level: process.env.LOG_LEVEL ?? "info" },
});

// ─── GET / — Dashboard ──────────────────────────────────────────────

fastify.get("/", async (_request, reply) => {
  reply.type("text/html").send(dashboardHtml());
});

// ─── GET /health ────────────────────────────────────────────────────

fastify.get("/health", async () => ({
  status: "ok",
  service: "portum",
  port: PORT,
  uptime: Math.floor(process.uptime()),
  totalRequests,
  totalErrors,
}));

// ─── GET /health/providers ──────────────────────────────────────────

fastify.get("/health/providers", async () => {
  const providers = getAllProviders();
  const results: Record<string, { configured: boolean; reachable: boolean | null; latencyMs: number | null; error: string | null }> = {};

  const checks = Object.entries(providers).map(async ([name, cfg]) => {
    const key = process.env[cfg.apiKeyEnv];
    if (!key) {
      results[name] = { configured: false, reachable: null, latencyMs: null, error: `Missing ${cfg.apiKeyEnv}` };
      return;
    }

    // Light HEAD/GET probe — just check the endpoint responds
    const start = Date.now();
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 5000);
      // Use a GET to the base domain — most providers return 200 or 404 without auth
      const baseUrl = new URL(cfg.url);
      const probeUrl = `${baseUrl.protocol}//${baseUrl.host}`;
      const res = await fetch(probeUrl, {
        method: "HEAD",
        signal: controller.signal,
      });
      clearTimeout(timeout);
      results[name] = {
        configured: true,
        reachable: res.status < 500,
        latencyMs: Date.now() - start,
        error: null,
      };
    } catch (err) {
      results[name] = {
        configured: true,
        reachable: false,
        latencyMs: Date.now() - start,
        error: err instanceof Error ? err.message : String(err),
      };
    }
  });

  await Promise.all(checks);
  return results;
});

// ─── GET /stats ─────────────────────────────────────────────────────

fastify.get("/stats", async () => {
  const topModels = Object.entries(modelCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([model, count]) => ({ model, count }));

  return {
    totalRequests,
    totalErrors,
    requestsPerProvider: requestCountsByProvider,
    averageResponseTimeMs: totalRequests === 0 ? 0 : Number((totalResponseTimeMs / totalRequests).toFixed(2)),
    totalTokens: {
      prompt_tokens: totalPromptTokens,
      completion_tokens: totalCompletionTokens,
      total_tokens: totalTokens,
    },
    totalCostUsd: Number(totalCostUsd.toFixed(6)),
    todayCostUsd: Number(todayCostUsd.toFixed(6)),
    topModels,
    recentRequests: auditLog.slice(-20).reverse(),
  };
});

// ─── GET /audit ─────────────────────────────────────────────────────

fastify.get("/audit", async () => ({
  count: auditLog.length,
  max: AUDIT_MAX,
  entries: [...auditLog].reverse(),
}));

// ─── GET /version ───────────────────────────────────────────────────

fastify.get("/version", async () => ({
  version: "1.0.0",
  name: "portum",
}));

// ─── POST /v1/chat/completions ──────────────────────────────────────

fastify.post(
  "/v1/chat/completions",
  {
    schema: {
      body: {
        type: "object",
        required: ["model", "messages"],
        properties: {
          model: { type: "string", minLength: 1 },
          messages: {
            type: "array",
            minItems: 1,
            items: {
              type: "object",
              required: ["role", "content"],
              properties: {
                role: { type: "string" },
                content: {},
                name: { type: "string" },
              },
            },
          },
          max_tokens: { type: "integer", minimum: 1 },
          temperature: { type: "number" },
          stream: { type: "boolean" },
        },
      },
    },
  },
  async (
    request: FastifyRequest<{ Body: ChatCompletionRequest }>,
    reply: FastifyReply,
  ) => {
    const { body } = request;
    const result = await routeRequest(body);
    const entry = recordAudit(result, body);
    recordStats(entry);

    request.log.info({
      id: entry.id,
      model: body.model,
      provider: result.provider,
      responseTimeMs: result.responseTimeMs,
      usage: result.response.usage,
      costUsd: result.estimatedCostUsd,
      status: entry.status,
    }, "chat.completions");

    if (result.error) {
      return reply.code(result.error.status).send({
        error: {
          message: result.error.message,
          type: "routing_error",
          code: result.error.status,
        },
      });
    }

    return reply.send(result.response);
  },
);

