<script>
const POLL_MS = 3000;
let lastAuditId = 0;

async function refresh() {
  try {
    const [stats, audit, health] = await Promise.all([
      fetch('/stats').then(r => r.json()),
      fetch('/audit').then(r => r.json()),
      fetch('/health/providers').then(r => r.json()),
    ]);

    // Banner
    document.getElementById('b-reqs').textContent = String(stats.totalRequests);
    document.getElementById('b-cost').textContent = '$' + Number(stats.todayCostUsd).toFixed(4);

    // Vitals
    const avgMs = stats.averageResponseTimeMs || 0;
    document.getElementById('vitals').innerHTML = [
      vital('Total Requests', stats.totalRequests, ''),
      vital('Avg Latency', avgMs.toFixed(0) + 'ms', avgMs > 2000 ? 'red' : ''),
      vital('Total Tokens', fmt(stats.totalTokens.total_tokens), ''),
      vital('Total Spend', '$' + Number(stats.totalCostUsd).toFixed(4), 'teal'),
    ].join('');

    // Providers
    const provHtml = Object.entries(stats.requestsPerProvider).map(([name, count]) => {
      const h = health[name];
      const dotCls = !h ? 'unknown' : h.configured ? (h.reachable ? 'on' : 'off') : 'off';
      return '<div class="prov"><div class="name">' + esc(name) + '</div><div class="count">' + count + '</div><div><span class="dot ' + dotCls + '"></span>' + (h?.configured ? (h.reachable ? 'up' : 'down') : 'no key') + '</div></div>';
    }).join('');
    document.getElementById('providers').innerHTML = provHtml;

    // Top models
    if (stats.topModels.length > 0) {
      document.getElementById('top-models').innerHTML = stats.topModels.map(m =>
        '<span class="model-chip">' + esc(m.model) + '<span class="n">' + m.count + '</span></span>'
      ).join('');
    }

    // Feed
    if (audit.entries.length > 0) {
      const empty = document.getElementById('feed-empty');
      if (empty) empty.remove();

      const newEntries = audit.entries.filter(e => e.id > lastAuditId);
      if (newEntries.length > 0) {
        lastAuditId = audit.entries[0].id;
        const feed = document.getElementById('feed');
        // Rebuild feed from audit (newest first, keep header)
        const header = feed.querySelector('.header');
        feed.innerHTML = '';
        if (header) feed.appendChild(header);
        for (const e of audit.entries) {
          const t = new Date(e.timestamp);
          const ts = t.toLocaleTimeString();
          const stCls = e.status === 'ok' ? 'ok' : 'error';
          const row = document.createElement('div');
          row.className = 'feed-row';
          row.innerHTML =
            '<span class="ts">' + ts + '</span>' +
            '<span class="pv">' + esc(e.provider) + '</span>' +
            '<span class="mdl">' + esc(e.model) + '</span>' +
            '<span class="ms">' + e.responseTimeMs + 'ms</span>' +
            '<span class="tok">' + fmt(e.usage.total_tokens) + '</span>' +
            '<span class="cst">$' + Number(e.estimatedCostUsd).toFixed(4) + '</span>' +
            '<span class="st ' + stCls + '">' + e.status + '</span>';
          feed.appendChild(row);
        }
      }
    }
  } catch (err) {
    console.error('Dashboard poll failed:', err);
  }
}

function vital(label, value, cls) {
