}
html,body{
  margin:0;min-height:100%;
  background:
    radial-gradient(ellipse 70% 55% at 50% 42%,transparent 24%,rgba(0,0,4,.82) 100%),
    radial-gradient(circle at 8% 12%,rgba(111,217,255,.16),transparent 34%),
    radial-gradient(circle at 92% 8%,rgba(77,245,200,.14),transparent 36%),
    radial-gradient(circle at 6% 94%,rgba(177,150,255,.14),transparent 38%),
    radial-gradient(circle at 94% 96%,rgba(251,146,60,.12),transparent 38%),
    linear-gradient(180deg,#020617 0%,#01030d 46%,#020818 100%);
  color:var(--ink);font-family:var(--body);-webkit-font-smoothing:antialiased;
}
body::before{
  content:"";position:fixed;inset:0;pointer-events:none;
  background-image:linear-gradient(rgba(140,220,255,.03) 1px,transparent 1px),linear-gradient(90deg,rgba(140,220,255,.03) 1px,transparent 1px);
  background-size:40px 40px;mask-image:radial-gradient(circle,black 38%,transparent 100%);opacity:.22;z-index:0;
}
@keyframes flow{0%{background-position:0% 50%}100%{background-position:200% 50%}}
@keyframes dotPulse{0%,100%{opacity:.72;transform:scale(1)}50%{opacity:1;transform:scale(1.15)}}

.shell{max-width:1200px;margin:0 auto;padding:22px;display:grid;gap:16px;position:relative;z-index:1}

.banner{
  padding:22px 28px;border-radius:24px;
  border:1px solid rgba(140,220,255,.22);
  background:radial-gradient(ellipse 60% 80% at 50% 50%,rgba(30,90,160,.22),transparent 62%),linear-gradient(180deg,rgba(4,12,28,.88),rgba(2,6,18,.94));
  box-shadow:var(--bubble-glow);
