}
.banner::before{content:"";position:absolute;top:0;left:6%;right:6%;height:2px;background:var(--current);background-size:200% 100%;opacity:.85;animation:flow 10s linear infinite;pointer-events:none}
.banner-title{font-size:clamp(28px,3.5vw,44px);font-weight:700;letter-spacing:.06em;text-shadow:0 0 18px rgba(251,146,60,.42)}
.banner-sub{font-family:var(--mono);font-size:10px;letter-spacing:.3em;text-transform:uppercase;color:var(--ink-soft)}
.banner-stats{display:flex;gap:20px;align-items:center}
.banner-stat{text-align:right}
.banner-stat .val{font-family:var(--mono);font-size:clamp(24px,3vw,36px);font-weight:500;color:var(--teal);text-shadow:0 0 18px rgba(77,245,200,.32)}
.banner-stat .lbl{font-family:var(--mono);font-size:9px;letter-spacing:.3em;text-transform:uppercase;color:var(--ink-soft)}

.panel{
  border-radius:20px;padding:18px;
  border:1px solid rgba(120,200,255,.18);
  background:radial-gradient(ellipse 80% 120% at 50% -10%,rgba(111,217,255,.08),transparent 60%),linear-gradient(180deg,rgba(4,10,24,.82),rgba(2,6,16,.92));
