.panel-title{font-family:var(--mono);font-size:10px;letter-spacing:.22em;text-transform:uppercase;color:var(--ink-soft);margin-bottom:14px}

.vitals{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}
.vital{
  padding:16px;border-radius:18px;
  border:1px solid rgba(120,200,255,.18);
  background:radial-gradient(ellipse 80% 120% at 50% -20%,rgba(111,217,255,.1),transparent 60%),linear-gradient(180deg,rgba(4,10,24,.82),rgba(2,6,16,.92));
