.vital .val.teal{color:var(--teal);text-shadow:0 0 14px rgba(77,245,200,.32)}
.vital .val.red{color:var(--red)}

.providers{display:grid;grid-template-columns:repeat(5,1fr);gap:10px}
.prov{
  padding:12px;border-radius:14px;text-align:center;
  border:1px solid rgba(120,200,255,.14);
  background:linear-gradient(180deg,rgba(4,10,24,.82),rgba(2,6,16,.92));
}
.prov .name{font-family:var(--mono);font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--orange)}
.prov .count{font-family:var(--mono);font-size:22px;color:var(--teal);margin:6px 0 2px}
.prov .dot{display:inline-block;width:8px;height:8px;border-radius:50%;margin-right:4px}
.prov .dot.on{background:var(--teal);box-shadow:0 0 10px var(--teal)}
.prov .dot.off{background:var(--red);box-shadow:0 0 10px var(--red)}
.prov .dot.unknown{background:rgba(255,255,255,.2)}

.feed{max-height:420px;overflow-y:auto;display:grid;gap:6px}
.feed-row{
  display:grid;grid-template-columns:140px 100px minmax(120px,1fr) 80px 90px 80px 70px;gap:10px;
  align-items:center;padding:8px 12px;border-radius:10px;
