}
.feed-row.header{color:var(--ink-soft);letter-spacing:.14em;text-transform:uppercase;font-size:9px;border:none;background:none;padding-bottom:4px}
.feed-row .ts{color:var(--ink-dim)}
.feed-row .pv{color:var(--cyan)}
.feed-row .mdl{color:var(--orange);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.feed-row .ms{color:var(--ink-soft)}
.feed-row .tok{color:var(--violet)}
.feed-row .cst{color:var(--teal)}
.feed-row .st{font-weight:500}
.feed-row .st.ok{color:var(--teal)}
.feed-row .st.error{color:var(--red)}

.top-models{display:flex;flex-wrap:wrap;gap:8px}
.model-chip{
  padding:6px 12px;border-radius:999px;
  border:1px solid rgba(120,200,255,.22);
  background:linear-gradient(180deg,rgba(111,217,255,.06),rgba(177,150,255,.04));
  font-family:var(--mono);font-size:10px;letter-spacing:.1em;color:var(--ink-soft);
}
.model-chip .n{color:var(--teal);margin-left:6px}

.empty{
  text-align:center;padding:28px;color:var(--ink-dim);
  font-family:var(--mono);font-size:12px;letter-spacing:.08em;
  border:1px dashed rgba(120,200,255,.12);border-radius:14px;
}

@media(max-width:900px){
  .vitals,.providers{grid-template-columns:repeat(2,1fr)}
  .feed-row{grid-template-columns:100px 80px 1fr 60px 60px;font-size:10px}
  .feed-row .tok,.feed-row .cst{display:none}
  .banner{flex-direction:column;text-align:center}
}
</style>
</head>
<body>
<div class="shell">
  <div class="banner">
    <div>
      <div class="banner-title">PORTUM</div>
      <div class="banner-sub">Universal AI Gateway</div>
    </div>
    <div class="banner-stats">
      <div class="banner-stat"><div class="val teal" id="b-reqs">0</div><div class="lbl">Requests</div></div>
      <div class="banner-stat"><div class="val teal" id="b-cost">$0.00</div><div class="lbl">Today</div></div>
    </div>
  </div>

  <div class="vitals" id="vitals"></div>

  <div class="panel">
    <div class="panel-title">Providers</div>
    <div class="providers" id="providers"></div>
  </div>

  <div class="panel">
    <div class="panel-title">Top Models</div>
    <div class="top-models" id="top-models"><div class="empty">No requests yet</div></div>
  </div>

  <div class="panel">
    <div class="panel-title">Live Request Feed</div>
    <div class="feed" id="feed">
      <div class="feed-row header">
        <span>Time</span><span>Provider</span><span>Model</span><span>Latency</span><span>Tokens</span><span>Cost</span><span>Status</span>
      </div>
      <div class="empty" id="feed-empty">Waiting for requests...</div>
    </div>
  </div>
</div>

<script>
const POLL_MS = 3000;
let lastAuditId = 0;

async function refresh() {
  try {
    const [stats, audit, health] = await Promise.all([
      fetch('/stats').then(r => r.json()),
      fetch('/audit').then(r => r.json()),
      fetch('/health/providers').then(r => r.json()),
    ]);

    // Banner
    document.getElementById('b-reqs').textContent = String(stats.totalRequests);
    document.getElementById('b-cost').textContent = '$' + Number(stats.todayCostUsd).toFixed(4);

    // Vitals
    const avgMs = stats.averageResponseTimeMs || 0;
    document.getElementById('vitals').innerHTML = [
      vital('Total Requests', stats.totalRequests, ''),
      vital('Avg Latency', avgMs.toFixed(0) + 'ms', avgMs > 2000 ? 'red' : ''),
      vital('Total Tokens', fmt(stats.totalTokens.total_tokens), ''),
      vital('Total Spend', '$' + Number(stats.totalCostUsd).toFixed(4), 'teal'),
    ].join('');

    // Providers
    const provHtml = Object.entries(stats.requestsPerProvider).map(([name, count]) => {
      const h = health[name];
      const dotCls = !h ? 'unknown' : h.configured ? (h.reachable ? 'on' : 'off') : 'off';
      return '<div class="prov"><div class="name">' + esc(name) + '</div><div class="count">' + count + '</div><div><span class="dot ' + dotCls + '"></span>' + (h?.configured ? (h.reachable ? 'up' : 'down') : 'no key') + '</div></div>';
    }).join('');
    document.getElementById('providers').innerHTML = provHtml;

    // Top models
    if (stats.topModels.length > 0) {
      document.getElementById('top-models').innerHTML = stats.topModels.map(m =>
        '<span class="model-chip">' + esc(m.model) + '<span class="n">' + m.count + '</span></span>'
      ).join('');
    }

    // Feed
    if (audit.entries.length > 0) {
      const empty = document.getElementById('feed-empty');
      if (empty) empty.remove();

      const newEntries = audit.entries.filter(e => e.id > lastAuditId);
      if (newEntries.length > 0) {
        lastAuditId = audit.entries[0].id;
        const feed = document.getElementById('feed');
        // Rebuild feed from audit (newest first, keep header)
        const header = feed.querySelector('.header');
        feed.innerHTML = '';
        if (header) feed.appendChild(header);
        for (const e of audit.entries) {
          const t = new Date(e.timestamp);
          const ts = t.toLocaleTimeString();
          const stCls = e.status === 'ok' ? 'ok' : 'error';
          const row = document.createElement('div');
          row.className = 'feed-row';
          row.innerHTML =
            '<span class="ts">' + ts + '</span>' +
            '<span class="pv">' + esc(e.provider) + '</span>' +
            '<span class="mdl">' + esc(e.model) + '</span>' +
            '<span class="ms">' + e.responseTimeMs + 'ms</span>' +
            '<span class="tok">' + fmt(e.usage.total_tokens) + '</span>' +
            '<span class="cst">$' + Number(e.estimatedCostUsd).toFixed(4) + '</span>' +
            '<span class="st ' + stCls + '">' + e.status + '</span>';
          feed.appendChild(row);
        }
      }
    }
  } catch (err) {
    console.error('Dashboard poll failed:', err);
  }
}

function vital(label, value, cls) {
  return '<div class="vital"><div class="lbl">' + label + '</div><div class="val ' + cls + '">' + value + '</div></div>';
}

function fmt(n) {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
  return String(n);
}

function esc(s) {
  const d = document.createElement('div');
  d.textContent = String(s);
  return d.innerHTML;
}

refresh();
setInterval(refresh, POLL_MS);
</script>
</body>
</html>`;
}

// ─── Boot ───────────────────────────────────────────────────────────

async function start(): Promise<void> {
  try {
    await fastify.listen({ port: PORT, host: HOST });
    fastify.log.info(`Portum listening on http://${HOST}:${PORT}`);
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
}

start();
",
            "content": "/**
 * Portum — OpenAI-compatible chat completions gateway.
 *
 * Endpoints:
 *   POST /v1/chat/completions  — route to upstream provider
 *   GET  /health               — basic health check
 *   GET  /health/providers     — per-provider key + reachability check
 *   GET  /stats                — aggregate stats
 *   GET  /audit                — last 50 requests with full detail
 *   GET  /                     — live dashboard (HTML)
 *   GET  /version              — version information
 */

import Fastify, { type FastifyReply, type FastifyRequest } from "fastify";
import {
  routeRequest,
  getProviderForModel,
  getAllProviders,
  type ChatCompletionRequest,
  type ChatCompletionResponse,
  type ChatCompletionUsage,
  type ProviderName,
  type RouteResult,
} from "./router.js";

const PORT = Number(process.env.PORT ?? 18797);
const HOST = process.env.HOST ?? "0.0.0.0";

// ─── Audit Log ──────────────────────────────────────────────────────

interface AuditEntry {
  id: number;
  timestamp: string;
  model: string;
  provider: ProviderName;
  responseTimeMs: number;
  usage: ChatCompletionUsage;
  estimatedCostUsd: number;
  status: "ok" | "error";
  errorMessage: string | null;
  responsePreview: string;
}

const AUDIT_MAX = 50;
const auditLog: AuditEntry[] = [];
let auditSeq = 0;

function recordAudit(result: RouteResult, request: ChatCompletionRequest): AuditEntry {
  const preview = result.error
    ? result.error.message.slice(0, 200)
    : (result.response.choices[0]?.message?.content ?? "").slice(0, 200);

  const entry: AuditEntry = {
    id: ++auditSeq,
    timestamp: new Date().toISOString(),
    model: request.model,
    provider: result.provider,
    responseTimeMs: result.responseTimeMs,
    usage: result.response.usage,
    estimatedCostUsd: result.estimatedCostUsd,
    status: result.error ? "error" : "ok",
    errorMessage: result.error?.message ?? null,
    responsePreview: preview,
  };

  auditLog.push(entry);
  if (auditLog.length > AUDIT_MAX) auditLog.shift();
  return entry;
}

// ─── Aggregate Stats ────────────────────────────────────────────────

const requestCountsByProvider: Record<ProviderName, number> = {
  openai: 0,
  anthropic: 0,
  modelstudio: 0,
  minimax: 0,
  openrouter: 0,
};
const modelCounts: Record<string, number> = {};

let totalRequests = 0;
let totalErrors = 0;
let totalResponseTimeMs = 0;
let totalPromptTokens = 0;
let totalCompletionTokens = 0;
let totalTokens = 0;
let totalCostUsd = 0;
const todayStart = new Date(); todayStart.setHours(0, 0, 0, 0);
let todayCostUsd = 0;

function recordStats(entry: AuditEntry): void {
  totalRequests += 1;
  if (entry.status === "error") totalErrors += 1;
  requestCountsByProvider[entry.provider] += 1;
  totalResponseTimeMs += entry.responseTimeMs;
  totalPromptTokens += entry.usage.prompt_tokens;
  totalCompletionTokens += entry.usage.completion_tokens;
  totalTokens += entry.usage.total_tokens;
  totalCostUsd += entry.estimatedCostUsd;
  modelCounts[entry.model] = (modelCounts[entry.model] ?? 0) + 1;

  if (new Date(entry.timestamp) >= todayStart) {
    todayCostUsd += entry.estimatedCostUsd;
  }
}

// ─── Server ─────────────────────────────────────────────────────────

const fastify = Fastify({
  logger: { level: process.env.LOG_LEVEL ?? "info" },
});

// ─── GET / — Dashboard ──────────────────────────────────────────────

fastify.get("/", async (_request, reply) => {
  reply.type("text/html").send(dashboardHtml());
});

// ─── GET /health ────────────────────────────────────────────────────

fastify.get("/health", async () => ({
  status: "ok",
  service: "portum",
  port: PORT,
  uptime: Math.floor(process.uptime()),
  totalRequests,
  totalErrors,
}));

// ─── GET /health/providers ──────────────────────────────────────────

fastify.get("/health/providers", async () => {
  const providers = getAllProviders();
  const results: Record<string, { configured: boolean; reachable: boolean | null; latencyMs: number | null; error: string | null }> = {};

  const checks = Object.entries(providers).map(async ([name, cfg]) => {
    const key = process.env[cfg.apiKeyEnv];
    if (!key) {
      results[name] = { configured: false, reachable: null, latencyMs: null, error: `Missing ${cfg.apiKeyEnv}` };
      return;
    }

    // Light HEAD/GET probe — just check the endpoint responds
    const start = Date.now();
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 5000);
      // Use a GET to the base domain — most providers return 200 or 404 without auth
      const baseUrl = new URL(cfg.url);
      const probeUrl = `${baseUrl.protocol}//${baseUrl.host}`;
      const res = await fetch(probeUrl, {
        method: "HEAD",
        signal: controller.signal,
      });
      clearTimeout(timeout);
      results[name] = {
        configured: true,
        reachable: res.status < 500,
        latencyMs: Date.now() - start,
        error: null,
      };
    } catch (err) {
      results[name] = {
        configured: true,
        reachable: false,
        latencyMs: Date.now() - start,
        error: err instanceof Error ? err.message : String(err),
      };
    }
  });

  await Promise.all(checks);
  return results;
});

// ─── GET /stats ─────────────────────────────────────────────────────

fastify.get("/stats", async () => {
  const topModels = Object.entries(modelCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([model, count]) => ({ model, count }));

  return {
    totalRequests,
    totalErrors,
    requestsPerProvider: requestCountsByProvider,
    averageResponseTimeMs: totalRequests === 0 ? 0 : Number((totalResponseTimeMs / totalRequests).toFixed(2)),
    totalTokens: {
      prompt_tokens: totalPromptTokens,
      completion_tokens: totalCompletionTokens,
      total_tokens: totalTokens,
    },
    totalCostUsd: Number(totalCostUsd.toFixed(6)),
    todayCostUsd: Number(todayCostUsd.toFixed(6)),
    topModels,
    recentRequests: auditLog.slice(-20).reverse(),
  };
});

// ─── GET /audit ─────────────────────────────────────────────────────

fastify.get("/audit", async () => ({
  count: auditLog.length,
  max: AUDIT_MAX,
  entries: [...auditLog].reverse(),
}));

// ─── GET /version ───────────────────────────────────────────────────

fastify.get("/version", async () => ({
  version: "1.0.0",
  name: "portum",
}));

// ─── POST /v1/chat/completions ──────────────────────────────────────

fastify.post(
  "/v1/chat/completions",
  {
    schema: {
      body: {
        type: "object",
        required: ["model", "messages"],
        properties: {
          model: { type: "string", minLength: 1 },
          messages: {
            type: "array",
            minItems: 1,
            items: {
              type: "object",
              required: ["role", "content"],
              properties: {
                role: { type: "string" },
                content: {},
                name: { type: "string" },
              },
            },
          },
          max_tokens: { type: "integer", minimum: 1 },
          temperature: { type: "number" },
          stream: { type: "boolean" },
        },
      },
    },
  },
  async (
    request: FastifyRequest<{ Body: ChatCompletionRequest }>,
    reply: FastifyReply,
  ) => {
    const { body } = request;
    const result = await routeRequest(body);
    const entry = recordAudit(result, body);
    recordStats(entry);

    request.log.info({
      id: entry.id,
      model: body.model,
      provider: result.provider,
      responseTimeMs: result.responseTimeMs,
      usage: result.response.usage,
      costUsd: result.estimatedCostUsd,
      status: entry.status,
    }, "chat.completions");

    if (result.error) {
      return reply.code(result.error.status).send({
        error: {
          message: result.error.message,
          type: "routing_error",
          code: result.error.status,
        },
      });
    }

    return reply.send(result.response);
  },
);

