@keyframes flow{0%{background-position:0% 50%}100%{background-position:200% 50%}}
@keyframes dotPulse{0%,100%{opacity:.72;transform:scale(1)}50%{opacity:1;transform:scale(1.15)}}

.shell{max-width:1200px;margin:0 auto;padding:22px;display:grid;gap:16px;position:relative;z-index:1}

.banner{
  padding:22px 28px;border-radius:24px;
  border:1px solid rgba(140,220,255,.22);
  background:radial-gradient(ellipse 60% 80% at 50% 50%,rgba(30,90,160,.22),transparent 62%),linear-gradient(180deg,rgba(4,12,28,.88),rgba(2,6,18,.94));
  box-shadow:var(--bubble-glow);
  display:flex;align-items:center;justify-content:space-between;gap:24px;
  position:relative;overflow:hidden;
}
.banner::before{content:"";position:absolute;top:0;left:6%;right:6%;height:2px;background:var(--current);background-size:200% 100%;opacity:.85;animation:flow 10s linear infinite;pointer-events:none}
.banner-title{font-size:clamp(28px,3.5vw,44px);font-weight:700;letter-spacing:.06em;text-shadow:0 0 18px rgba(251,146,60,.42)}
.banner-sub{font-family:var(--mono);font-size:10px;letter-spacing:.3em;text-transform:uppercase;color:var(--ink-soft)}
.banner-stats{display:flex;gap:20px;align-items:center}
.banner-stat{text-align:right}
.banner-stat .val{font-family:var(--mono);font-size:clamp(24px,3vw,36px);font-weight:500;color:var(--teal);text-shadow:0 0 18px rgba(77,245,200,.32)}
.banner-stat .lbl{font-family:var(--mono);font-size:9px;letter-spacing:.3em;text-transform:uppercase;color:var(--ink-soft)}

.panel{
  border-radius:20px;padding:18px;
  border:1px solid rgba(120,200,255,.18);
  background:radial-gradient(ellipse 80% 120% at 50% -10%,rgba(111,217,255,.08),transparent 60%),linear-gradient(180deg,rgba(4,10,24,.82),rgba(2,6,16,.92));
  box-shadow:var(--bubble-glow);position:relative;overflow:hidden;
}
.panel::before{content:"";position:absolute;top:0;left:8%;right:8%;height:1px;background:var(--current);background-size:200% 100%;opacity:.7;animation:flow 14s linear infinite;pointer-events:none}
.panel-title{font-family:var(--mono);font-size:10px;letter-spacing:.22em;text-transform:uppercase;color:var(--ink-soft);margin-bottom:14px}

.vitals{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}
.vital{
  padding:16px;border-radius:18px;
  border:1px solid rgba(120,200,255,.18);
  background:radial-gradient(ellipse 80% 120% at 50% -20%,rgba(111,217,255,.1),transparent 60%),linear-gradient(180deg,rgba(4,10,24,.82),rgba(2,6,16,.92));
  box-shadow:var(--bubble-glow);position:relative;overflow:hidden;
}
.vital::before{content:"";position:absolute;top:0;left:14%;right:14%;height:1px;background:var(--current);background-size:200% 100%;opacity:.6;animation:flow 16s linear infinite;pointer-events:none}
.vital .lbl{font-family:var(--mono);font-size:9px;letter-spacing:.3em;text-transform:uppercase;color:var(--ink-soft)}
.vital .val{font-family:var(--mono);font-size:clamp(22px,2.6vw,34px);font-weight:500;line-height:.9;margin-top:8px;color:var(--orange);text-shadow:0 0 14px rgba(251,146,60,.28)}
.vital .val.teal{color:var(--teal);text-shadow:0 0 14px rgba(77,245,200,.32)}
.vital .val.red{color:var(--red)}

.providers{display:grid;grid-template-columns:repeat(5,1fr);gap:10px}
.prov{
  padding:12px;border-radius:14px;text-align:center;
  border:1px solid rgba(120,200,255,.14);
  background:linear-gradient(180deg,rgba(4,10,24,.82),rgba(2,6,16,.92));
}
.prov .name{font-family:var(--mono);font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--orange)}
.prov .count{font-family:var(--mono);font-size:22px;color:var(--teal);margin:6px 0 2px}
.prov .dot{display:inline-block;width:8px;height:8px;border-radius:50%;margin-right:4px}
.prov .dot.on{background:var(--teal);box-shadow:0 0 10px var(--teal)}
.prov .dot.off{background:var(--red);box-shadow:0 0 10px var(--red)}
.prov .dot.unknown{background:rgba(255,255,255,.2)}

.feed{max-height:420px;overflow-y:auto;display:grid;gap:6px}
.feed-row{
  display:grid;grid-template-columns:140px 100px minmax(120px,1fr) 80px 90px 80px 70px;gap:10px;
  align-items:center;padding:8px 12px;border-radius:10px;
  background:rgba(4,10,24,.6);border:1px solid rgba(120,200,255,.08);
  font-family:var(--mono);font-size:11px;
}
.feed-row.header{color:var(--ink-soft);letter-spacing:.14em;text-transform:uppercase;font-size:9px;border:none;background:none;padding-bottom:4px}
.feed-row .ts{color:var(--ink-dim)}
.feed-row .pv{color:var(--cyan)}
.feed-row .mdl{color:var(--orange);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.feed-row .ms{color:var(--ink-soft)}
.feed-row .tok{color:var(--violet)}
.feed-row .cst{color:var(--teal)}
.feed-row .st{font-weight:500}
.feed-row .st.ok{color:var(--teal)}
.feed-row .st.error{color:var(--red)}

.top-models{display:flex;flex-wrap:wrap;gap:8px}
.model-chip{
  padding:6px 12px;border-radius:999px;
  border:1px solid rgba(120,200,255,.22);
  background:linear-gradient(180deg,rgba(111,217,255,.06),rgba(177,150,255,.04));
  font-family:var(--mono);font-size:10px;letter-spacing:.1em;color:var(--ink-soft);
}
.model-chip .n{color:var(--teal);margin-left:6px}

.empty{
  text-align:center;padding:28px;color:var(--ink-dim);
  font-family:var(--mono);font-size:12px;letter-spacing:.08em;
  border:1px dashed rgba(120,200,255,.12);border-radius:14px;
}

@media(max-width:900px){
  .vitals,.providers{grid-template-columns:repeat(2,1fr)}
  .feed-row{grid-template-columns:100px 80px 1fr 60px 60px;font-size:10px}
  .feed-row .tok,.feed-row .cst{display:none}
  .banner{flex-direction:column;text-align:center}
}
</style>
</head>
<body>
<div class="shell">
  <div class="banner">
    <div>
      <div class="banner-title">PORTUM</div>
      <div class="banner-sub">Universal AI Gateway</div>
    </div>
    <div class="banner-stats">
      <div class="banner-stat"><div class="val teal" id="b-reqs">0</div><div class="lbl">Requests</div></div>
      <div class="banner-stat"><div class="val teal" id="b-cost">$0.00</div><div class="lbl">Today</div></div>
    </div>
  </div>

  <div class="vitals" id="vitals"></div>

  <div class="panel">
    <div class="panel-title">Providers</div>
    <div class="providers" id="providers"></div>
  </div>

  <div class="panel">
    <div class="panel-title">Top Models</div>
    <div class="top-models" id="top-models"><div class="empty">No requests yet</div></div>
  </div>

  <div class="panel">
    <div class="panel-title">Live Request Feed</div>
    <div class="feed" id="feed">
      <div class="feed-row header">
        <span>Time</span><span>Provider</span><span>Model</span><span>Latency</span><span>Tokens</span><span>Cost</span><span>Status</span>
      </div>
      <div class="empty" id="feed-empty">Waiting for requests...</div>
    </div>
  </div>
</div>

<script>
const POLL_MS = 3000;
let lastAuditId = 0;

async function refresh() {
  try {
    const [stats, audit, health] = await Promise.all([
      fetch('/stats').then(r => r.json()),
      fetch('/audit').then(r => r.json()),
      fetch('/health/providers').then(r => r.json()),
    ]);

    // Banner
    document.getElementById('b-reqs').textContent = String(stats.totalRequests);
    document.getElementById('b-cost').textContent = '$' + Number(stats.todayCostUsd).toFixed(4);

    // Vitals
    const avgMs = stats.averageResponseTimeMs || 0;
    document.getElementById('vitals').innerHTML = [
      vital('Total Requests', stats.totalRequests, ''),
      vital('Avg Latency', avgMs.toFixed(0) + 'ms', avgMs > 2000 ? 'red' : ''),
      vital('Total Tokens', fmt(stats.totalTokens.total_tokens), ''),
      vital('Total Spend', '$' + Number(stats.totalCostUsd).toFixed(4), 'teal'),
    ].join('');

    // Providers
    const provHtml = Object.entries(stats.requestsPerProvider).map(([name, count]) => {
      const h = health[name];
      const dotCls = !h ? 'unknown' : h.configured ? (h.reachable ? 'on' : 'off') : 'off';
      return '<div class="prov"><div class="name">' + esc(name) + '</div><div class="count">' + count + '</div><div><span class="dot ' + dotCls + '"></span>' + (h?.configured ? (h.reachable ? 'up' : 'down') : 'no key') + '</div></div>';
    }).join('');
    document.getElementById('providers').innerHTML = provHtml;

    // Top models
    if (stats.topModels.length > 0) {
      document.getElementById('top-models').innerHTML = stats.topModels.map(m =>
        '<span class="model-chip">' + esc(m.model) + '<span class="n">' + m.count + '</span></span>'
      ).join('');
    }

    // Feed
    if (audit.entries.length > 0) {
      const empty = document.getElementById('feed-empty');
      if (empty) empty.remove();

      const newEntries = audit.entries.filter(e => e.id > lastAuditId);
      if (newEntries.length > 0) {
        lastAuditId = audit.entries[0].id;
        const feed = document.getElementById('feed');
        // Rebuild feed from audit (newest first, keep header)
        const header = feed.querySelector('.header');
        feed.innerHTML = '';
        if (header) feed.appendChild(header);
        for (const e of audit.entries) {
          const t = new Date(e.timestamp);
          const ts = t.toLocaleTimeString();
          const stCls = e.status === 'ok' ? 'ok' : 'error';
          const row = document.createElement('div');
          row.className = 'feed-row';
          row.innerHTML =
            '<span class="ts">' + ts + '</span>' +
            '<span class="pv">' + esc(e.provider) + '</span>' +
            '<span class="mdl">' + esc(e.model) + '</span>' +
            '<span class="ms">' + e.responseTimeMs + 'ms</span>' +
            '<span class="tok">' + fmt(e.usage.total_tokens) + '</span>' +
            '<span class="cst">$' + Number(e.estimatedCostUsd).toFixed(4) + '</span>' +
            '<span class="st ' + stCls + '">' + e.status + '</span>';
          feed.appendChild(row);
        }
      }
    }
  } catch (err) {
    console.error('Dashboard poll failed:', err);
  }
}

function vital(label, value, cls) {
  return '<div class="vital"><div class="lbl">' + label + '</div><div class="val ' + cls + '">' + value + '</div></div>';
}

function fmt(n) {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
  return String(n);
}

function esc(s) {
  const d = document.createElement('div');
  d.textContent = String(s);
  return d.innerHTML;
}

refresh();
setInterval(refresh, POLL_MS);
</script>
</body>
</html>`;
}

// ─── Boot ───────────────────────────────────────────────────────────

async function start(): Promise<void> {
  try {
    await fastify.listen({ port: PORT, host: HOST });
    fastify.log.info(`Portum listening on http://${HOST}:${PORT}`);
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
}

start();
